#define THREADS_PER_BLOCK 256
#define MAXBLOCKS 65536

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

kernel void kernel_compute_cost(int num, int dim, long x, Point_Struct *p, int K, int stride,
                    float *coord_d, float *work_mem_d, int *center_table_d, char *switch_membership_d)
{
    const int bid  = get_group_id(0) + get_num_groups(0) * get_group_id(1);
    const int tid = get_local_size(0) * bid + get_local_id(0);

    if(num > tid)
    {
        float *lower = &work_mem_d[tid*stride];

        float x_cost = 0.0f;
        for(int i = 0; i < dim; i++){
            float tmp = coord_d[(i*num)+tid] - coord_d[(i*num)+x];
            x_cost += tmp * tmp;
        }
        x_cost *= p[tid].weight;

        if ( p[tid].cost > x_cost )
        {
            switch_membership_d[tid] = 1;
            lower[K] += x_cost - p[tid].cost;
        }
        else
        {
            lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
        }
    }
}
